  ('locality-6e11b43e-moex-00235', 'locality-6e11b43e', 'locality-6e11b43e-moex-111-3082b5f1', 'sub-locality-6e11b43e-03', NULL, 'single_choice', '國防部核定甲因病死亡辦理撫卹，甲之父乙未於法定救濟期間內提起行政救濟。嗣甲之班長丙因 凌虐甲，犯凌虐部屬致死罪，經法院判決確定。依據該確定判決，甲符合軍人撫卹條例因公死亡 之要件。關於乙之救濟，下列敘述何者正確？', '["確定判決係作成行政處分後之證據，乙不得申請另為核定處分", "依行政程序法申請行政程序重開", "提起訴願法上之再審", "提起行政訴訟法上之再審"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:32+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "304", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
